// Offline navbar collapse behavior for this Bootstrap-compatible build.
(function () {
    document.addEventListener('click', function (event) {
        var button = event.target.closest('[data-bs-toggle="collapse"]');
        if (!button) {
            return;
        }
        var target = document.querySelector(button.getAttribute('data-bs-target'));
        if (!target) {
            return;
        }
        var open = target.classList.toggle('show');
        button.setAttribute('aria-expanded', open ? 'true' : 'false');
    });
})();
